import{c as a,Q as e,j as r,m as d}from"./chunks/framework.rlpw0eGz.js";const b=JSON.parse('{"title":"机器人的渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/channels.md","filePath":"zh/getting-started/channels.md","lastUpdated":1777012567000}'),h={name:"zh/getting-started/channels.md"};function o(n,t,l,s,i,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="机器人的渠道" tabindex="-1">机器人的渠道 <a class="header-anchor" href="#机器人的渠道" aria-label="Permalink to &quot;机器人的渠道&quot;">​</a></h1><p><strong>渠道</strong>把机器人接到各消息平台，让你用熟悉的 App 跟它说话。</p><h2 id="统一接入" tabindex="-1">统一接入 <a class="header-anchor" href="#统一接入" aria-label="Permalink to &quot;统一接入&quot;">​</a></h2><p>Memoh 在中间做一层适配；一个机器人可以同时挂在 Telegram、Discord、Matrix 等多个平台。</p><hr><h2 id="支持哪些平台" tabindex="-1">支持哪些平台 <a class="header-anchor" href="#支持哪些平台" aria-label="Permalink to &quot;支持哪些平台&quot;">​</a></h2><p>在机器人 <strong>Platforms</strong> tab 里配。分平台步骤见 <strong><a href="/zh/channels/index.html">渠道</a></strong> 下各篇：</p><table tabindex="0"><thead><tr><th>平台</th><th>指南</th><th>备注</th></tr></thead><tbody><tr><td>Telegram</td><td><a href="/zh/channels/telegram.html">Telegram</a></td><td>附件、流式较好</td></tr><tr><td>飞书</td><td><a href="/zh/channels/feishu.html">飞书</a></td><td>可走 webhook 入站</td></tr><tr><td>Discord</td><td><a href="/zh/channels/discord.html">Discord</a></td><td>社群、服务器</td></tr><tr><td>QQ</td><td><a href="/zh/channels/qq.html">QQ</a></td><td>偏个人 DM</td></tr><tr><td>Matrix</td><td><a href="/zh/channels/matrix.html">Matrix</a></td><td>自建 homeserver</td></tr><tr><td>Misskey</td><td><a href="/zh/channels/misskey.html">Misskey</a></td><td>回复、反应；无流式</td></tr><tr><td>钉钉</td><td><a href="/zh/channels/dingtalk.html">钉钉</a></td><td>企业私聊/群</td></tr><tr><td>企微</td><td><a href="/zh/channels/wecom.html">企微</a></td><td>企业微信工作区</td></tr><tr><td>微信</td><td><a href="/zh/channels/weixin.html">微信</a></td><td>个人扫码登录</td></tr><tr><td>公众号</td><td><a href="/zh/channels/wechatoa.html">公众号</a></td><td>公众号 webhook</td></tr><tr><td>Slack</td><td><a href="/zh/channels/slack.html">Slack</a></td><td>有 thread；无流式</td></tr></tbody></table><p>个人 <strong>微信</strong> 和 <strong>公众号</strong> 是两套适配，别混用。</p><hr><h2 id="配置流程" tabindex="-1">配置流程 <a class="header-anchor" href="#配置流程" aria-label="Permalink to &quot;配置流程&quot;">​</a></h2><h3 id="_1-添加" tabindex="-1">1. 添加 <a class="header-anchor" href="#_1-添加" aria-label="Permalink to &quot;1. 添加&quot;">​</a></h3><p><strong>Add Channel</strong> → 选平台 → 按表单填（随平台变）。</p><h3 id="_2-常见字段" tabindex="-1">2. 常见字段 <a class="header-anchor" href="#_2-常见字段" aria-label="Permalink to &quot;2. 常见字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>Credentials</strong></td><td>各平台给的 token、密钥、机器人 key 等</td></tr><tr><td><strong>Disabled</strong></td><td>不删配置，只关掉</td></tr><tr><td><strong>Routing</strong></td><td>平台侧线程/会话与 Memoh 的对应关系</td></tr></tbody></table><h3 id="_3-飞书-webhook-入站" tabindex="-1">3. 飞书 Webhook 入站 <a class="header-anchor" href="#_3-飞书-webhook-入站" aria-label="Permalink to &quot;3. 飞书 Webhook 入站&quot;">​</a></h3><p><code>webhook</code> 入站时，Memoh 会生成 <strong>Webhook 回调 URL</strong>，贴到飞书应用事件里，由飞书把消息推过来。</p><h3 id="_4-个人微信" tabindex="-1">4. 个人微信 <a class="header-anchor" href="#_4-个人微信" aria-label="Permalink to &quot;4. 个人微信&quot;">​</a></h3><p>启用后走扫码，用微信扫完连上。</p><h3 id="_5-公众号" tabindex="-1">5. 公众号 <a class="header-anchor" href="#_5-公众号" aria-label="Permalink to &quot;5. 公众号&quot;">​</a></h3><p>先保存渠道，用 Memoh 给的 <strong>回调 URL</strong> 配到公众号后台；<code>Token</code>、加解密方式、可选 AES 要与 Memoh 里一致。</p><h3 id="_6-钉钉-stream" tabindex="-1">6. 钉钉 Stream <a class="header-anchor" href="#_6-钉钉-stream" aria-label="Permalink to &quot;6. 钉钉 Stream&quot;">​</a></h3><p>填 <code>App Key</code> / <code>App Secret</code>，保存并启用；标准用法下由 Memoh 维护长连接收事件，不必自己再管一层 webhook。</p><hr><h2 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h2><ul><li><strong>Save</strong>：改配置</li><li><strong>Save and Enable</strong>：保存并立刻启用</li><li><strong>启停开关</strong>：不删配置地开/关</li><li><strong>Delete</strong>：删掉该渠道配置</li></ul>',26)])])}const g=a(h,[["render",o]]);export{b as __pageData,g as default};
